using QBEngineer.Core.Entities;
using QBEngineer.Core.Enums;
using QBEngineer.Data.Context;

using Serilog;

namespace QBEngineer.Api.Data.TrainingContent;

public class EdiTraining : TrainingContentBase
{
    public EdiTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "EDI Overview",
            Slug = "edi-overview",
            Summary = "What EDI is, the X12 and EDIFACT formats, how trading partners, transactions, and mappings work together in QB Engineer.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/admin/edi"]""",
            Tags = """["edi","admin","integrations"]""",
            ContentJson = """{"body":"## EDI Overview\n\nElectronic Data Interchange (EDI) lets your shop exchange structured business documents — purchase orders, invoices, shipping notices, and more — with trading partners electronically instead of through paper, email, or manual data entry.\n\nQB Engineer's EDI module lives under Admin > EDI and gives you a central place to manage trading partners, monitor inbound and outbound transactions, configure field mappings, and handle errors with retry support.\n\n### What Is EDI?\n\nEDI replaces manual document exchange with standardized electronic formats. When a customer sends you a purchase order via EDI, it arrives as a structured data file that QB Engineer can parse, validate, and automatically apply — creating a Sales Order, Purchase Order, or other entity without anyone retyping the information.\n\nThe reverse also works: when you ship an order, QB Engineer can generate an outbound EDI document (like an ASN or invoice) and send it to the trading partner automatically.\n\n### EDI Formats\n\nQB Engineer supports two major EDI standards:\n\n- **X12** — The dominant standard in North America. Transaction sets are identified by three-digit numbers: 850 (Purchase Order), 810 (Invoice), 856 (Advance Ship Notice), 855 (PO Acknowledgment), and many more.\n- **EDIFACT** — The international standard used widely outside the US. Uses alphabetic message type codes like ORDERS, INVOIC, DESADV.\n\nEach trading partner is configured with a default format, but individual transactions can use either format.\n\n### Trading Partners\n\nA trading partner is any company you exchange EDI documents with — typically customers or vendors. Each partner record stores:\n\n- **EDI identifiers** — Qualifier ID and Qualifier Value that uniquely identify the partner in EDI envelopes. The Interchange Sender/Receiver IDs and Application Sender/Receiver IDs route documents correctly.\n- **Format and transport** — Whether the partner uses X12 or EDIFACT, and how documents are delivered (AS2, SFTP, VAN, Email, API, or Manual).\n- **Processing rules** — Whether inbound documents are auto-processed or held for manual review, and whether the partner requires functional acknowledgments (997/CONTRL).\n- **Links** — A partner can be linked to an existing Customer or Vendor record in QB Engineer for automatic entity matching.\n\n### Transactions\n\nEvery EDI document exchange creates a transaction record. Transactions track:\n\n- **Direction** — Inbound (received from partner) or Outbound (sent to partner).\n- **Transaction Set** — The document type (e.g., 850 for a Purchase Order, 810 for an Invoice).\n- **Control Numbers** — Interchange, Group, and Transaction control numbers that uniquely identify the document in the EDI envelope.\n- **Status lifecycle** — Each transaction moves through a processing pipeline: Received → Parsing → Parsed → Validating → Validated → Processing → Applied (success) or Error/Rejected (failure).\n- **Related entity** — Once processed, the transaction links to the QB Engineer entity it created or updated (e.g., a Sales Order, PO, or Invoice).\n- **Error handling** — Failed transactions show the error message and can be retried. The retry count and last retry timestamp are tracked.\n- **Acknowledgments** — When a partner requires acknowledgments, the system tracks whether the 997/CONTRL was sent and links the acknowledgment transaction.\n\n### Mappings\n\nMappings define how fields in an EDI document translate to fields in QB Engineer entities. Each mapping belongs to a trading partner and a specific transaction set.\n\n- **Field mappings** — Map EDI segment/element paths to QB Engineer entity fields (e.g., PO1-07 → Part Number, N1-04 → Customer ID).\n- **Value translations** — Convert partner-specific codes to QB Engineer values (e.g., partner's item code '12345' maps to your Part Number 'WIDGET-001').\n- **Default mapping** — One mapping per transaction set can be marked as default. When a document arrives, the system uses the default mapping unless overridden.\n\n### Transport Methods\n\nQB Engineer supports multiple ways to send and receive EDI documents:\n\n- **AS2** — The most common B2B protocol. Encrypted, signed, with built-in receipt (MDN) support.\n- **SFTP** — Secure file transfer. Documents are placed in partner-specific directories.\n- **VAN** — Value Added Network. A third-party service that routes documents between partners (e.g., SPS Commerce, TrueCommerce).\n- **Email** — EDI documents sent as email attachments. Simple but less automated.\n- **API** — Direct REST/SOAP API integration with the partner's system.\n- **Manual** — Documents are uploaded/downloaded manually through the QB Engineer UI. Good for low-volume partners or testing.\n\n### Inbound Polling and Auto-Processing\n\nWhen Auto Process is enabled on a trading partner, QB Engineer automatically processes inbound documents through the full pipeline — parsing the EDI content, validating against the mapping rules, and applying the data to create or update entities. When Auto Process is off, inbound documents stop at the Received status for manual review before processing.\n\n### When to Use EDI\n\n- When a customer or vendor requires electronic document exchange\n- When you want to eliminate manual data entry for recurring orders\n- When you need an auditable trail of every document exchanged with a partner\n- When your trading partner uses a VAN or AS2 and expects automated acknowledgments","sections":[]}"""
        });

        // ── Walkthrough ──────────────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "EDI — Guided Tour",
            Slug = "edi-walkthrough",
            Summary = "A guided tour of the Admin > EDI page: sub-tabs, trading partner table, partner dialog, transaction list, filters, transaction detail, and retry.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 6,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/admin/edi"]""",
            Tags = """["edi","admin","walkthrough"]""",
            ContentJson = """{"appRoute":"/admin/edi","startButtonLabel":"Tour EDI","steps":[{"element":".edi-panel .tab-bar","popover":{"title":"EDI Sub-Tabs","description":"The EDI page has two sub-tabs: Trading Partners (manage your EDI partner configurations) and Transactions (monitor all inbound and outbound EDI document exchanges). Click a tab to switch views.","side":"bottom"}},{"element":".edi-panel__toolbar .action-btn--primary","popover":{"title":"New Trading Partner","description":"Click here to add a new trading partner. You'll enter the partner name, EDI qualifier IDs, default format (X12 or EDIFACT), transport method, and processing rules. The partner can optionally be linked to an existing Customer or Vendor.","side":"bottom"}},{"element":"app-data-table[tableId='edi-partners']","popover":{"title":"Trading Partners Table","description":"Lists all configured trading partners. Columns show the partner name, linked customer/vendor, default format, transport method, transaction count, error count, and active status. Click column headers to sort. Each row has action buttons for testing the connection, editing, and deleting.","side":"top"}},{"element":".tab:nth-child(2)","popover":{"title":"Transactions Tab","description":"Switch to the Transactions tab to see all EDI document exchanges. Each row shows the trading partner, direction (Inbound/Outbound), transaction set code, control number, processing status, related entity, received timestamp, and retry count.","side":"bottom"}}]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "EDI Field Reference",
            Slug = "edi-field-reference",
            Summary = "Complete reference for every field, status, format, transport method, button, and validation rule in the EDI module.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/admin/edi"]""",
            Tags = """["edi","admin","reference"]""",
            ContentJson = """{"title":"EDI Field Reference","groups":[{"heading":"Trading Partner Form Fields","items":[{"label":"Name (required)","value":"Text input, max 200 characters. The display name for this trading partner (e.g., 'Acme Corp EDI', 'SPS Commerce - Grainger')."},{"label":"Qualifier ID (required)","value":"Text input, max 10 characters. The EDI qualifier code that identifies how the partner's ID is formatted. Default: 'ZZ' (Mutually Defined). Common values: '01' (DUNS), '08' (UCC/EAN), '12' (Phone), '14' (DUNS+4), 'ZZ' (Mutually Defined)."},{"label":"Qualifier Value (required)","value":"Text input, max 100 characters. The actual partner identifier value corresponding to the Qualifier ID (e.g., a DUNS number, phone number, or mutually agreed code)."},{"label":"Default Format (required)","value":"Dropdown: X12, EDIFACT. The default EDI standard for this partner. X12 is the North American standard; EDIFACT is the international standard. Default: X12."},{"label":"Transport Method (required)","value":"Dropdown: AS2, SFTP, VAN, Email, API, Manual. How EDI documents are sent to and received from this partner. Default: Manual."},{"label":"Auto Process (toggle)","value":"When ON (default), inbound documents are automatically parsed, validated, and applied. When OFF, documents stop at Received status for manual review."},{"label":"Require Acknowledgment (toggle)","value":"When ON (default), the system sends functional acknowledgments (997 for X12, CONTRL for EDIFACT) for received documents. The acknowledgment transaction is linked to the original."},{"label":"Notes","value":"Textarea, optional. Free-form notes about the trading partner — connection details, contact info, special requirements, or integration notes."}]},{"heading":"Trading Partner Table Columns","items":[{"label":"Name","value":"Sortable. Partner display name."},{"label":"Customer","value":"Sortable. Linked customer name, or '—' if not linked."},{"label":"Vendor","value":"Sortable. Linked vendor name, or '—' if not linked."},{"label":"Format","value":"Sortable. Default EDI format: X12 or EDIFACT."},{"label":"Transport","value":"Sortable. Transport method: AS2, SFTP, VAN, Email, API, or Manual."},{"label":"Txns","value":"Sortable, right-aligned. Total number of transactions for this partner."},{"label":"Errors","value":"Sortable, right-aligned. Number of transactions in Error status. Displayed as a red chip when > 0."},{"label":"Active","value":"Center-aligned. Green check_circle icon when active, gray cancel icon when inactive."},{"label":"Actions","value":"Three icon buttons: Test Connection (wifi_tethering), Edit (edit), Delete (delete, danger style)."}]},{"heading":"Transaction Table Columns","items":[{"label":"Partner","value":"Sortable. Trading partner name."},{"label":"Dir","value":"Sortable, filterable (enum). Direction: Inbound (blue chip) or Outbound (primary chip)."},{"label":"Set","value":"Sortable, center-aligned. Transaction set code (e.g., 850, 810, 856 for X12)."},{"label":"Control #","value":"Sortable. Interchange control number for document identification."},{"label":"Status","value":"Sortable, filterable (enum). Color-coded chip showing processing status."},{"label":"Entity","value":"Sortable. Related entity type (e.g., SalesOrder, PurchaseOrder) or '—' if not yet applied."},{"label":"Received","value":"Sortable, date type. Timestamp when the document was received, formatted MM/dd/yyyy HH:mm."},{"label":"Retries","value":"Sortable, right-aligned. Number of retry attempts for failed transactions."},{"label":"Actions","value":"Retry button (refresh icon) appears only for transactions in Error status."}]},{"heading":"Transaction Detail Fields","items":[{"label":"Partner","value":"Display only. The trading partner name associated with this transaction."},{"label":"Direction","value":"Display only. Inbound (blue chip) or Outbound (primary chip)."},{"label":"Transaction Set","value":"Display only. The document type code (e.g., 850, 810, 856)."},{"label":"Status","value":"Display only. Color-coded chip showing current processing status."},{"label":"Error Message","value":"Display only. Shown in a red error box when the transaction has an error. Describes what went wrong during parsing, validation, or processing."},{"label":"Raw Payload","value":"Display only. The full raw EDI document content in a monospace code block. Shows the actual X12 segments or EDIFACT messages as received/sent."},{"label":"Parsed Data","value":"Display only. The parsed JSON representation of the EDI document, shown when parsing succeeded. Displays the structured data extracted from the raw payload."}]},{"heading":"Transaction Statuses","items":[{"label":"Received (blue/info chip)","value":"Document received but not yet processed. This is the initial status for all inbound documents, and the holding status when Auto Process is off."},{"label":"Parsing (yellow/warning chip)","value":"Document is being parsed from raw EDI format into structured data."},{"label":"Parsed (default chip)","value":"Parsing completed successfully. The raw EDI has been converted to structured JSON."},{"label":"Validating (yellow/warning chip)","value":"Parsed data is being validated against mapping rules and business logic."},{"label":"Validated (default chip)","value":"Validation passed. Data is ready for processing."},{"label":"Processing (yellow/warning chip)","value":"Data is being applied to QB Engineer entities (creating/updating Sales Orders, POs, etc.)."},{"label":"Applied (green/success chip)","value":"Transaction successfully processed. The related entity has been created or updated. The Related Entity column shows what was created."},{"label":"Error (red/error chip)","value":"Processing failed at some stage. The error message describes the issue. A Retry button appears in the actions column."},{"label":"Acknowledged (gray/muted chip)","value":"A functional acknowledgment (997/CONTRL) has been sent for this inbound transaction."},{"label":"Rejected (red/error chip)","value":"The document was rejected during validation — the data did not meet the required rules or the trading partner's mapping could not be applied."}]},{"heading":"EDI Formats","items":[{"label":"X12","value":"ANSI ASC X12 standard. Dominant in North America. Transaction sets identified by 3-digit numbers (850=PO, 810=Invoice, 856=ASN, 855=PO Ack, 997=Functional Ack). Segments delimited by ~ (tilde), elements by * (asterisk)."},{"label":"EDIFACT","value":"UN/EDIFACT international standard. Used globally, especially in Europe and Asia. Message types use alphabetic codes (ORDERS, INVOIC, DESADV, CONTRL). Segments delimited by ' (apostrophe), elements by + (plus)."}]},{"heading":"Transport Methods","items":[{"label":"AS2","value":"Applicability Statement 2. The most common B2B EDI protocol. Uses HTTP/HTTPS with encryption (S/MIME), digital signatures, and Message Disposition Notifications (MDN) for delivery confirmation."},{"label":"SFTP","value":"SSH File Transfer Protocol. Documents are placed in partner-specific directories on a secure server. Simple, reliable, widely supported."},{"label":"VAN","value":"Value Added Network. A third-party service (e.g., SPS Commerce, TrueCommerce, Cleo) that routes documents between trading partners. Handles format translation, compliance checking, and delivery."},{"label":"Email","value":"EDI documents sent as email attachments. Low automation, typically used for low-volume partners or as a fallback."},{"label":"API","value":"Direct REST or SOAP API integration with the partner's system. Modern alternative to traditional EDI transport."},{"label":"Manual","value":"Documents uploaded and downloaded manually through the QB Engineer UI. Best for testing, low-volume partners, or initial setup before automating transport."}]},{"heading":"Mapping Fields","items":[{"label":"Transaction Set","value":"The EDI document type this mapping applies to (e.g., 850, 810). Each mapping is scoped to one transaction set per trading partner."},{"label":"Name","value":"Display name for the mapping profile (e.g., 'Acme PO Mapping', 'Standard 810 Invoice')."},{"label":"Field Mappings (JSON)","value":"Array of field-to-field mappings. Each entry maps an EDI segment/element path (e.g., PO1-07) to a QB Engineer entity field (e.g., partNumber). Stored as JSON."},{"label":"Value Translations (JSON)","value":"Array of value translation rules. Converts partner-specific codes to QB Engineer values (e.g., partner item code → your part number). Stored as JSON."},{"label":"Is Default","value":"Toggle. When ON, this mapping is automatically used for the specified transaction set from this partner. Only one mapping per transaction set can be default."},{"label":"Notes","value":"Optional notes about the mapping — field explanations, partner requirements, version history."}]},{"heading":"Buttons and Actions","items":[{"label":"New Trading Partner","value":"Primary button in the toolbar (Partners tab). Opens the partner creation dialog."},{"label":"Test Connection","value":"wifi_tethering icon button in partner row actions. Sends a connectivity test to the partner's configured transport endpoint. Shows success or failure snackbar."},{"label":"Edit Partner","value":"edit icon button in partner row actions. Opens the partner dialog pre-filled with current values."},{"label":"Delete Partner","value":"delete icon button (danger style) in partner row actions. Soft-deletes the trading partner."},{"label":"Retry Transaction","value":"refresh icon button in transaction row actions. Only visible for transactions in Error status. Re-queues the transaction for processing. Shows 'Retry queued' snackbar."},{"label":"View Transaction","value":"Click any transaction row to open the detail dialog showing partner, direction, set, status, raw payload, parsed data, and errors."},{"label":"Close (transaction detail)","value":"Primary button in the transaction detail dialog footer. Closes the detail view."},{"label":"Save / Create (partner dialog)","value":"Primary button in the partner dialog footer. Creates or updates the trading partner. Disabled when the form is invalid or save is in progress. Hovering when disabled shows a validation popover."},{"label":"Cancel (partner dialog)","value":"Secondary button in the partner dialog footer. Closes the dialog without saving."}]},{"heading":"Validation Rules","items":[{"label":"Name","value":"Required. Must not be empty. Maximum 200 characters."},{"label":"Qualifier ID","value":"Required. Must not be empty. Maximum 10 characters. Default: 'ZZ'."},{"label":"Qualifier Value","value":"Required. Must not be empty. Maximum 100 characters."},{"label":"Default Format","value":"Required. Must be X12 or EDIFACT."},{"label":"Transport Method","value":"Required. Must be one of: AS2, SFTP, VAN, Email, API, Manual."},{"label":"Submit button","value":"Disabled when form is invalid or saving. Hovering over the disabled button shows a validation popover listing which fields need attention."}]},{"heading":"Transaction Filters","items":[{"label":"Direction filter","value":"Dropdown: All (default), Inbound, Outbound. Filters the transaction list by document direction."},{"label":"Status filter","value":"Dropdown: All (default), Received, Parsing, Parsed, Processing, Applied, Error, Acknowledged, Rejected. Filters by processing status."},{"label":"Filter behavior","value":"Selecting any filter value immediately refreshes the transaction list from the API with the applied filters."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "EDI Knowledge Check",
            Slug = "edi-quiz",
            Summary = "Test your knowledge of the EDI module: formats, trading partners, transactions, mappings, statuses, and transport methods.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/training"]""",
            Tags = """["edi","admin","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"edi1","text":"A new customer requires EDI document exchange for purchase orders. Where do you set this up in QB Engineer?","options":[{"id":"a","text":"Go to Customers, open the customer detail, and enable the EDI toggle"},{"id":"b","text":"Navigate to Admin > EDI, click New Trading Partner, and configure the partner with the customer's EDI identifiers, format, and transport method","isCorrect":true},{"id":"c","text":"Create a new integration in Admin > Integrations and select EDI as the type"},{"id":"d","text":"Go to Admin > Settings and add the customer's EDI credentials to the system settings"}],"explanation":"Trading partners are managed under Admin > EDI. Click New Trading Partner and fill in the name, qualifier ID/value, default format (X12 or EDIFACT), transport method, and processing rules. You can link the partner to an existing Customer record."},{"id":"edi2","text":"What is the difference between X12 and EDIFACT?","options":[{"id":"a","text":"X12 is for invoices only, EDIFACT is for purchase orders only"},{"id":"b","text":"X12 is the North American standard using numeric transaction set codes (like 850, 810); EDIFACT is the international standard using alphabetic message types (like ORDERS, INVOIC)","isCorrect":true},{"id":"c","text":"X12 is newer and replaces EDIFACT, which is deprecated"},{"id":"d","text":"X12 only works with AS2 transport, while EDIFACT only works with SFTP"}],"explanation":"X12 (ANSI ASC X12) is the dominant standard in North America, using 3-digit numeric codes for transaction sets (850=Purchase Order, 810=Invoice). EDIFACT (UN/EDIFACT) is the international standard using alphabetic codes (ORDERS, INVOIC). Both are actively used."},{"id":"edi3","text":"You see a transaction in the Transactions tab with status 'Error' (red chip). What action can you take?","options":[{"id":"a","text":"Delete the transaction and ask the partner to resend"},{"id":"b","text":"Click the transaction row to view the error details, then click the Retry button to re-queue it for processing","isCorrect":true},{"id":"c","text":"Change the status manually to Applied to force it through"},{"id":"d","text":"Nothing — error transactions are permanently failed and must be handled outside QB Engineer"}],"explanation":"Transactions in Error status show a Retry button (refresh icon) in the actions column. Click the row to see the error message and raw payload in the detail dialog, then click Retry to re-queue the transaction for processing. The retry count tracks how many attempts have been made."},{"id":"edi4","text":"What does the 'Auto Process' toggle on a trading partner control?","options":[{"id":"a","text":"Whether outbound documents are sent automatically or queued for manual review"},{"id":"b","text":"Whether inbound documents are automatically parsed, validated, and applied, or held at Received status for manual review","isCorrect":true},{"id":"c","text":"Whether the partner's connection is tested automatically every hour"},{"id":"d","text":"Whether duplicate documents from this partner are automatically rejected"}],"explanation":"When Auto Process is ON (default), inbound EDI documents are automatically processed through the full pipeline: Received → Parsing → Parsed → Validating → Validated → Processing → Applied. When OFF, documents stop at the Received status and require manual action to proceed."},{"id":"edi5","text":"A trading partner's Qualifier ID is set to 'ZZ'. What does this mean?","options":[{"id":"a","text":"The partner uses a ZIP code as their identifier"},{"id":"b","text":"The identifier type is 'Mutually Defined' — the Qualifier Value is a code agreed upon by both parties","isCorrect":true},{"id":"c","text":"The partner has not been fully configured yet and 'ZZ' is a placeholder"},{"id":"d","text":"The partner uses a DUNS number for identification"}],"explanation":"'ZZ' is the EDI qualifier code for 'Mutually Defined,' meaning both trading partners have agreed on the format and meaning of the Qualifier Value. It is the most common qualifier when partners don't use a standard identifier like DUNS ('01') or UCC/EAN ('08'). It is also the default in QB Engineer."},{"id":"edi6","text":"What is the purpose of an EDI mapping in QB Engineer?","options":[{"id":"a","text":"It maps the network route between your server and the partner's server for document delivery"},{"id":"b","text":"It defines how fields in an EDI document translate to fields in QB Engineer entities, and how partner-specific codes convert to your internal values","isCorrect":true},{"id":"c","text":"It creates a visual diagram of the EDI data flow for documentation purposes"},{"id":"d","text":"It maps user roles to EDI permissions so only authorized users can send documents"}],"explanation":"EDI mappings define two things: field mappings (which EDI segment/element maps to which QB Engineer field, like PO1-07 → Part Number) and value translations (converting partner-specific codes to your internal values, like their item code '12345' to your part number 'WIDGET-001')."},{"id":"edi7","text":"You want to see only inbound transactions that failed processing. How do you filter the transaction list?","options":[{"id":"a","text":"Set the Direction filter to Inbound and the Status filter to Error","isCorrect":true},{"id":"b","text":"Click the column header for Status and type 'Error' in the search box"},{"id":"c","text":"Use the search bar at the top and type 'Inbound Error'"},{"id":"d","text":"Switch to the Partners tab and look for partners with error counts > 0"}],"explanation":"The Transactions tab has two filter dropdowns at the top: Direction and Status. Set Direction to 'Inbound' and Status to 'Error' to see exactly the failed inbound transactions. The list refreshes immediately when you change either filter."},{"id":"edi8","text":"Which transport method provides built-in encryption, digital signatures, and delivery receipts (MDN)?","options":[{"id":"a","text":"SFTP"},{"id":"b","text":"Email"},{"id":"c","text":"AS2","isCorrect":true},{"id":"d","text":"VAN"}],"explanation":"AS2 (Applicability Statement 2) is the most common B2B EDI protocol. It uses HTTP/HTTPS with S/MIME encryption, digital signatures for authentication, and Message Disposition Notifications (MDN) to confirm delivery. It is the preferred transport for high-volume, security-sensitive EDI exchanges."},{"id":"edi9","text":"A trading partner has 'Require Acknowledgment' enabled. What happens when you receive an inbound document from them?","options":[{"id":"a","text":"QB Engineer sends a functional acknowledgment (997 for X12 or CONTRL for EDIFACT) back to the partner confirming receipt and processing status","isCorrect":true},{"id":"b","text":"QB Engineer sends an email notification to the admin user that a document was received"},{"id":"c","text":"The transaction is held until a user manually clicks an Acknowledge button"},{"id":"d","text":"The partner's system automatically marks the document as delivered without any action from QB Engineer"}],"explanation":"When Require Acknowledgment is ON, QB Engineer automatically sends a functional acknowledgment — a 997 transaction set for X12 or a CONTRL message for EDIFACT — back to the trading partner. The acknowledgment transaction is linked to the original inbound transaction for traceability."},{"id":"edi10","text":"What does the 'Test Connection' button (wifi icon) do on a trading partner row?","options":[{"id":"a","text":"Sends a test EDI document to the partner to verify end-to-end processing"},{"id":"b","text":"Sends a connectivity test to the partner's configured transport endpoint and reports success or failure via a snackbar message","isCorrect":true},{"id":"c","text":"Pings the partner's IP address to check if their server is online"},{"id":"d","text":"Toggles the partner between test mode and production mode"}],"explanation":"The Test Connection button sends a connectivity test to the partner's transport endpoint (AS2 URL, SFTP server, VAN mailbox, etc.). It shows a success snackbar if the connection succeeds or an error snackbar with the failure message if it doesn't. It does not send any actual EDI documents."},{"id":"edi11","text":"An EDI transaction shows a status of 'Acknowledged' (gray chip). What does this mean?","options":[{"id":"a","text":"The transaction was received but is waiting for a user to acknowledge and begin processing"},{"id":"b","text":"A functional acknowledgment (997/CONTRL) has been sent for this inbound transaction, confirming receipt to the trading partner","isCorrect":true},{"id":"c","text":"The related entity (e.g., Sales Order) has been acknowledged by the warehouse team"},{"id":"d","text":"The transaction failed but was acknowledged as a known issue that will not be retried"}],"explanation":"The Acknowledged status means a functional acknowledgment (997 for X12 or CONTRL for EDIFACT) was sent to the trading partner confirming that the inbound document was received and processed. The acknowledgment transaction is linked to the original for full traceability."},{"id":"edi12","text":"You need to set up EDI for a low-volume vendor who sends purchase orders occasionally. You are still configuring the integration. Which transport method is most appropriate to start with?","options":[{"id":"a","text":"AS2 — it is the industry standard and should be used from day one"},{"id":"b","text":"Manual — upload and download documents through the QB Engineer UI while you configure and test the full integration","isCorrect":true},{"id":"c","text":"VAN — always use a VAN for low-volume partners to reduce complexity"},{"id":"d","text":"API — set up a direct REST API connection for maximum speed"}],"explanation":"Manual transport lets you upload and download EDI documents directly through the QB Engineer UI. It is the best choice for initial setup, testing, and low-volume partners because it requires no external infrastructure. You can switch to AS2, SFTP, or a VAN later once the integration is validated."}]}"""
        });

        Log.Information("Seeded EDI training modules");
    }
}
